const label = (id,v) => setText(`label[for="${id}"]`, v);
const ph = (id,v) => { const n=$(`#${id}`); if(n) n.placeholder=v; };
const setBtn = (button, value) => { if(!button) return; const text=[...button.childNodes].find((n)=>n.nodeType===Node.TEXT_NODE && n.textContent.trim()); if(text) text.textContent = `\n${value}\n`; else button.append(value); };
function toast(msg,type=""){ const n=document.createElement("div"); n.className=`toast ${type}`.trim(); n.textContent=msg; el.toast?.appendChild(n); setTimeout(()=>n.remove(),3500); }
function busy(button,on,text){ if(!button) return; if(on){ button.dataset.label=button.textContent; button.textContent=text; button.disabled=true; } else { button.textContent=button.dataset.label || button.textContent; button.disabled=false; } }
