$("#member-role-filters")?.addEventListener("click",(e)=>{ const b=e.target.closest("button[data-role]"); if(!b) return; state.memberFilter=b.dataset.role; renderWorkspace(); }); el.chandaFilters?.addEventListener("click",(e)=>{ const b=e.target.closest("button[data-payment]"); if(!b) return; state.chandaFilter=b.dataset.payment; renderChanda(); }); el.kharchaFilters?.addEventListener("click",(e)=>{ const b=e.target.closest("button[data-category]"); if(!b) return; state.kharchaFilter=b.dataset.category; renderKharcha(); }); el.account.addEventListener("click",()=>showScreen(state.user?"temple":"account")); $("#google-signin-button").addEventListener("click",googleSignIn); el.logout.addEventListener("click",async()=>{await state.f.signOut(state.auth); toast(t("signedOut"),"success");}); el.createTempleForm.addEventListener("submit",createTemple); el.joinTempleForm.addEventListener("submit",requestAccess); el.renameTempleForm.addEventListener("submit",renameTemple); el.templeSwitcher.addEventListener("click",(e)=>{const b=e.target.closest("button[data-temple-id]"); if(b) activateTemple(state.memberships.find((m)=>m.templeId===b.dataset.templeId));}); const copyWorkspaceId=async()=>{try{await navigator.clipboard.writeText(state.activeMembership.templeId); toast(t("copied"),"success");}catch{toast(`Workspace ID: ${state.activeMembership.templeId}`);}}; $("#copy-workspace-id").addEventListener("click",copyWorkspaceId); document.querySelector("[data-copy-team-id]")?.addEventListener("click",copyWorkspaceId); document.querySelector("[data-copy-requests-id]")?.addEventListener("click",copyWorkspaceId);
const shareWorkspaceId=async()=>{ const tid=state.activeMembership?.templeId; if(!tid) return; const shareText=`DevNidhi Workspace ID: ${tid}`; if(navigator.share){ try{ await navigator.share({title:"DevNidhi",text:shareText}); return; }catch{ /* user cancelled or unsupported, fall through to copy */ } } try{ await navigator.clipboard.writeText(tid); toast(t("copied"),"success"); }catch{ toast(shareText); } }; $("#share-workspace-id")?.addEventListener("click",shareWorkspaceId); document.querySelector("[data-share-team-id]")?.addEventListener("click",shareWorkspaceId); document.querySelector("[data-team-invite]")?.addEventListener("click",shareWorkspaceId);
$$(".quick-tile-grid .quick-tile").forEach((btn)=>{ btn.addEventListener("click",()=>{ let target=null; if(btn.hasAttribute("data-focus-create")) target=el.createTempleForm; else if(btn.hasAttribute("data-focus-join")) target=el.joinTempleForm; else if(btn.hasAttribute("data-focus-share")||btn.hasAttribute("data-focus-details")) target=$(".workspace-info-card"); else if(btn.hasAttribute("data-focus-rename")) target=el.activeTempleCard; if(target&&!target.classList.contains("hidden")) target.scrollIntoView({behavior:"smooth",block:"start"}); else if(target===el.activeTempleCard) toast(t("adminNeeded")); }); });
