el.membersList.addEventListener("click",(e)=>{ const b=e.target.closest("button[data-action]"); if(!b) return; const details=b.closest("details.kebab-menu"); if(details) details.open=false; if(b.dataset.action==="set-admin") changeMemberRole(b.dataset.memberId,"admin"); else if(b.dataset.action==="set-viewer") changeMemberRole(b.dataset.memberId,"viewer"); else if(b.dataset.action==="remove-member") removeMember(b.dataset.memberId); }); document.addEventListener("toggle",(e)=>{ if(e.target&&e.target.matches&&e.target.matches("details.kebab-menu")&&e.target.open){ document.querySelectorAll("details.kebab-menu[open]").forEach((d)=>{ if(d!==e.target) d.open=false; }); } }, true); const requestActionHandler=async(e)=>{const b=e.target.closest("button[data-action]"); if(!b) return; if(b.dataset.action==="approve") await approveRequest(b.dataset.uid,b.dataset.role); if(b.dataset.action==="reject"&&confirm(t("rejectConfirm"))) await state.f.deleteDoc(state.f.doc(state.db,"temples",state.activeMembership.templeId,"joinRequests",b.dataset.uid));}; el.requestsList.addEventListener("click",requestActionHandler); el.requestsPreviewList?.addEventListener("click",requestActionHandler); el.chandaForm.addEventListener("submit",saveChanda); el.kharchaForm.addEventListener("submit",saveKharcha); el.chandaCancel.addEventListener("click",resetChanda); el.kharchaCancel.addEventListener("click",resetKharcha); el.chandaList.addEventListener("click",(e)=>entryAction(e,"chanda")); el.kharchaList.addEventListener("click",(e)=>entryAction(e,"kharcha")); const focusFormHandler=(e)=>{ const b=e.target.closest("button[data-focus-form]"); if(!b) return; const type=b.dataset.focusForm; showScreen(type); const panel=type==="chanda"?el.chandaPanel:el.kharchaPanel; if(panel?.classList.contains("hidden")) toast(t("adminNeeded")); else panel.scrollIntoView({behavior:"smooth",block:"start"}); }; el.chandaList.addEventListener("click",focusFormHandler); el.kharchaList.addEventListener("click",focusFormHandler); el.chandaSearch.addEventListener("input",renderChanda); el.kharchaSearch.addEventListener("input",renderKharcha);
function onlineStatus(){ el.offline.classList.toggle("show",!navigator.onLine); } window.addEventListener("online",()=>{onlineStatus();toast(t("backOnline"),"success");}); window.addEventListener("offline",onlineStatus); onlineStatus(); if("serviceWorker" in navigator) window.addEventListener("load",()=>navigator.serviceWorker.register("./service-worker.js").catch(console.warn)); resetChanda(); resetKharcha(); applyLanguage();

// --- Safety net: never let the loading screen hang forever (e.g. very slow network while Firebase SDK downloads) ---
let bootResolved=false;
const stopLoadingWithMessage=(msg)=>{ if(el.loading&&!el.loading.classList.contains("hidden")){ const txt=document.getElementById("loading-text"), retry=document.getElementById("loading-retry"); if(txt) txt.textContent=msg; if(retry){ retry.classList.remove("hidden"); retry.onclick=()=>location.reload(); } } };
const bootTimeout=setTimeout(()=>{ if(!bootResolved) stopLoadingWithMessage("Network slow lag raha hai ya connection weak hai. Wifi/data check karke Retry dabayein."); },14000);
window.addEventListener("error",(e)=>{ console.error(e.error||e.message); stopLoadingWithMessage("Kuch galat ho gaya. Retry dabayein."); });
window.addEventListener("unhandledrejection",(e)=>{ console.error(e.reason); stopLoadingWithMessage("Kuch galat ho gaya. Retry dabayein."); });

initialize().finally(()=>{ bootResolved=true; clearTimeout(bootTimeout); });
